CREATE TYPE "SubscriptionPlanCode" AS ENUM ('STARTER', 'PROFESSIONAL', 'BUSINESS', 'COMPANY');
CREATE TYPE "SubscriptionStatus" AS ENUM ('TRIALING', 'ACTIVE', 'PAST_DUE', 'SUSPENDED', 'CANCELED', 'EXPIRED');
CREATE TYPE "SubscriptionBillingCycle" AS ENUM ('MONTHLY', 'ANNUAL');
CREATE TYPE "SubscriptionChangeType" AS ENUM ('CREATED', 'TRIAL_STARTED', 'UPGRADED', 'DOWNGRADE_SCHEDULED', 'DOWNGRADED', 'CANCELED', 'REACTIVATED', 'SUSPENDED', 'RENEWED', 'LIMIT_CHANGED', 'ADDON_ADDED', 'ADDON_REMOVED', 'PROVIDER_EVENT', 'MANUAL_ADJUSTMENT');
CREATE TYPE "SubscriptionFeatureValueType" AS ENUM ('BOOLEAN', 'INTEGER', 'STRING', 'JSON');
CREATE TYPE "BillingProvider" AS ENUM ('MANUAL', 'MOCK');
CREATE TYPE "BillingProviderEventStatus" AS ENUM ('PENDING', 'PROCESSED', 'FAILED', 'IGNORED');

CREATE TABLE "subscription_plans" ("id" UUID NOT NULL, "code" "SubscriptionPlanCode" NOT NULL, "name" VARCHAR(160) NOT NULL, "description" TEXT, "positioning" TEXT, "is_active" BOOLEAN NOT NULL DEFAULT true, "is_public" BOOLEAN NOT NULL DEFAULT true, "display_order" INTEGER NOT NULL, "metadata" JSONB, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "subscription_plans_pkey" PRIMARY KEY ("id"));
CREATE TABLE "subscription_plan_prices" ("id" UUID NOT NULL, "plan_id" UUID NOT NULL, "billing_cycle" "SubscriptionBillingCycle" NOT NULL, "currency" VARCHAR(3) NOT NULL DEFAULT 'BRL', "amount_cents" INTEGER NOT NULL, "discount_percentage" INTEGER, "is_active" BOOLEAN NOT NULL DEFAULT true, "valid_from" TIMESTAMP(3), "valid_until" TIMESTAMP(3), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "subscription_plan_prices_pkey" PRIMARY KEY ("id"));
CREATE TABLE "subscription_features" ("id" UUID NOT NULL, "code" VARCHAR(120) NOT NULL, "name" VARCHAR(160) NOT NULL, "description" TEXT, "value_type" "SubscriptionFeatureValueType" NOT NULL, "category" VARCHAR(80) NOT NULL, "is_active" BOOLEAN NOT NULL DEFAULT true, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "subscription_features_pkey" PRIMARY KEY ("id"));
CREATE TABLE "subscription_plan_features" ("id" UUID NOT NULL, "plan_id" UUID NOT NULL, "feature_id" UUID NOT NULL, "enabled" BOOLEAN NOT NULL DEFAULT false, "integer_value" INTEGER, "string_value" TEXT, "json_value" JSONB, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "subscription_plan_features_pkey" PRIMARY KEY ("id"));
CREATE TABLE "subscriptions" ("id" UUID NOT NULL, "company_id" UUID NOT NULL, "plan_id" UUID NOT NULL, "plan_price_id" UUID NOT NULL, "status" "SubscriptionStatus" NOT NULL, "billing_cycle" "SubscriptionBillingCycle" NOT NULL, "provider" "BillingProvider" NOT NULL DEFAULT 'MANUAL', "external_subscription_id" VARCHAR(255), "trial_started_at" TIMESTAMP(3), "trial_ends_at" TIMESTAMP(3), "current_period_start" TIMESTAMP(3) NOT NULL, "current_period_end" TIMESTAMP(3) NOT NULL, "cancel_at_period_end" BOOLEAN NOT NULL DEFAULT false, "canceled_at" TIMESTAMP(3), "suspended_at" TIMESTAMP(3), "ended_at" TIMESTAMP(3), "next_plan_id" UUID, "next_plan_price_id" UUID, "next_plan_effective_at" TIMESTAMP(3), "metadata" JSONB, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "subscriptions_pkey" PRIMARY KEY ("id"));
CREATE TABLE "subscription_usage_counters" ("id" UUID NOT NULL, "subscription_id" UUID NOT NULL, "company_id" UUID NOT NULL, "usage_code" VARCHAR(120) NOT NULL, "period_start" TIMESTAMP(3) NOT NULL, "period_end" TIMESTAMP(3) NOT NULL, "quantity" INTEGER NOT NULL DEFAULT 0, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "subscription_usage_counters_pkey" PRIMARY KEY ("id"));
CREATE TABLE "subscription_usage" ("id" UUID NOT NULL, "subscription_id" UUID NOT NULL, "company_id" UUID NOT NULL, "usage_code" VARCHAR(120) NOT NULL, "quantity" INTEGER NOT NULL, "idempotency_key" VARCHAR(255) NOT NULL, "source_type" VARCHAR(80), "source_id" VARCHAR(255), "period_start" TIMESTAMP(3) NOT NULL, "period_end" TIMESTAMP(3) NOT NULL, "metadata" JSONB, "occurred_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "subscription_usage_pkey" PRIMARY KEY ("id"));
CREATE TABLE "subscription_history" ("id" UUID NOT NULL, "subscription_id" UUID NOT NULL, "company_id" UUID NOT NULL, "actor_id" UUID, "change_type" "SubscriptionChangeType" NOT NULL, "previous_plan_id" UUID, "next_plan_id" UUID, "previous_status" "SubscriptionStatus", "next_status" "SubscriptionStatus", "reason" TEXT, "request_id" VARCHAR(120), "previous_state" JSONB, "next_state" JSONB, "effective_at" TIMESTAMP(3) NOT NULL, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "subscription_history_pkey" PRIMARY KEY ("id"));
CREATE TABLE "billing_customers" ("id" UUID NOT NULL, "company_id" UUID NOT NULL, "provider" "BillingProvider" NOT NULL, "external_customer_id" VARCHAR(255), "email" VARCHAR(180), "metadata" JSONB, "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "billing_customers_pkey" PRIMARY KEY ("id"));
CREATE TABLE "billing_provider_events" ("id" UUID NOT NULL, "provider" "BillingProvider" NOT NULL, "external_event_id" VARCHAR(255) NOT NULL, "event_type" VARCHAR(120) NOT NULL, "status" "BillingProviderEventStatus" NOT NULL DEFAULT 'PENDING', "company_id" UUID, "subscription_id" UUID, "payload" JSONB NOT NULL, "error_message" TEXT, "processed_at" TIMESTAMP(3), "created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updated_at" TIMESTAMP(3) NOT NULL, CONSTRAINT "billing_provider_events_pkey" PRIMARY KEY ("id"));

CREATE UNIQUE INDEX "subscription_plans_code_key" ON "subscription_plans"("code");
CREATE INDEX "subscription_plans_display_order_idx" ON "subscription_plans"("display_order");
CREATE INDEX "subscription_plan_prices_plan_id_billing_cycle_is_active_idx" ON "subscription_plan_prices"("plan_id", "billing_cycle", "is_active");
CREATE UNIQUE INDEX "subscription_plan_prices_one_active_open_ended_per_cycle" ON "subscription_plan_prices"("plan_id", "billing_cycle") WHERE "is_active" = true AND "valid_from" IS NULL AND "valid_until" IS NULL;
CREATE UNIQUE INDEX "subscription_features_code_key" ON "subscription_features"("code");
CREATE UNIQUE INDEX "subscription_plan_features_plan_id_feature_id_key" ON "subscription_plan_features"("plan_id", "feature_id");
CREATE INDEX "subscriptions_company_id_status_idx" ON "subscriptions"("company_id", "status");
CREATE INDEX "subscriptions_current_period_end_idx" ON "subscriptions"("current_period_end");
CREATE UNIQUE INDEX "subscriptions_one_current_per_company" ON "subscriptions"("company_id") WHERE "status" IN ('TRIALING', 'ACTIVE', 'PAST_DUE', 'SUSPENDED');
CREATE UNIQUE INDEX "subscription_usage_counters_subscription_id_usage_code_period_start_period_end_key" ON "subscription_usage_counters"("subscription_id", "usage_code", "period_start", "period_end");
CREATE INDEX "subscription_usage_counters_company_id_usage_code_period_start_period_end_idx" ON "subscription_usage_counters"("company_id", "usage_code", "period_start", "period_end");
CREATE UNIQUE INDEX "subscription_usage_idempotency_key_key" ON "subscription_usage"("idempotency_key");
CREATE INDEX "subscription_usage_subscription_id_period_start_period_end_idx" ON "subscription_usage"("subscription_id", "period_start", "period_end");
CREATE INDEX "subscription_usage_company_id_usage_code_occurred_at_idx" ON "subscription_usage"("company_id", "usage_code", "occurred_at");
CREATE INDEX "subscription_history_subscription_id_effective_at_idx" ON "subscription_history"("subscription_id", "effective_at");
CREATE INDEX "subscription_history_company_id_effective_at_idx" ON "subscription_history"("company_id", "effective_at");
CREATE UNIQUE INDEX "billing_customers_company_id_provider_key" ON "billing_customers"("company_id", "provider");
CREATE UNIQUE INDEX "billing_provider_events_provider_external_event_id_key" ON "billing_provider_events"("provider", "external_event_id");
CREATE INDEX "billing_provider_events_company_id_idx" ON "billing_provider_events"("company_id");
CREATE INDEX "billing_provider_events_subscription_id_idx" ON "billing_provider_events"("subscription_id");

ALTER TABLE "subscription_plan_prices" ADD CONSTRAINT "subscription_plan_prices_plan_id_fkey" FOREIGN KEY ("plan_id") REFERENCES "subscription_plans"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_plan_features" ADD CONSTRAINT "subscription_plan_features_plan_id_fkey" FOREIGN KEY ("plan_id") REFERENCES "subscription_plans"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_plan_features" ADD CONSTRAINT "subscription_plan_features_feature_id_fkey" FOREIGN KEY ("feature_id") REFERENCES "subscription_features"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscriptions" ADD CONSTRAINT "subscriptions_company_id_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscriptions" ADD CONSTRAINT "subscriptions_plan_id_fkey" FOREIGN KEY ("plan_id") REFERENCES "subscription_plans"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscriptions" ADD CONSTRAINT "subscriptions_plan_price_id_fkey" FOREIGN KEY ("plan_price_id") REFERENCES "subscription_plan_prices"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscriptions" ADD CONSTRAINT "subscriptions_next_plan_id_fkey" FOREIGN KEY ("next_plan_id") REFERENCES "subscription_plans"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscriptions" ADD CONSTRAINT "subscriptions_next_plan_price_id_fkey" FOREIGN KEY ("next_plan_price_id") REFERENCES "subscription_plan_prices"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_usage_counters" ADD CONSTRAINT "subscription_usage_counters_subscription_id_fkey" FOREIGN KEY ("subscription_id") REFERENCES "subscriptions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_usage_counters" ADD CONSTRAINT "subscription_usage_counters_company_id_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_usage" ADD CONSTRAINT "subscription_usage_subscription_id_fkey" FOREIGN KEY ("subscription_id") REFERENCES "subscriptions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_usage" ADD CONSTRAINT "subscription_usage_company_id_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_history" ADD CONSTRAINT "subscription_history_subscription_id_fkey" FOREIGN KEY ("subscription_id") REFERENCES "subscriptions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_history" ADD CONSTRAINT "subscription_history_company_id_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_history" ADD CONSTRAINT "subscription_history_actor_id_fkey" FOREIGN KEY ("actor_id") REFERENCES "users"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "subscription_history" ADD CONSTRAINT "subscription_history_previous_plan_id_fkey" FOREIGN KEY ("previous_plan_id") REFERENCES "subscription_plans"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "subscription_history" ADD CONSTRAINT "subscription_history_next_plan_id_fkey" FOREIGN KEY ("next_plan_id") REFERENCES "subscription_plans"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "billing_customers" ADD CONSTRAINT "billing_customers_company_id_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "billing_provider_events" ADD CONSTRAINT "billing_provider_events_company_id_fkey" FOREIGN KEY ("company_id") REFERENCES "companies"("id") ON DELETE SET NULL ON UPDATE CASCADE;
